from dataclasses import dataclass
from datetime import datetime

@dataclass
class CustomerCommitment:
    ticket_id: str
    commitment_text: str         # exact text sent to customer
    committed_by: str            # agent handle
    deadline_utc: datetime
    requires_tier: str           # "L1", "L2", or "L3" for fulfilment
    fulfilled: bool = False

    def hours_to_deadline(self, as_of: datetime | None = None) -> float:
        ref = as_of or datetime.utcnow()
        return (self.deadline_utc - ref).total_seconds() / 3600

    def is_at_risk(self, as_of: datetime | None = None) -> bool:
        return not self.fulfilled and self.hours_to_deadline(as_of) < 1.0

def check_incoming_commitments(
    commitments: list[CustomerCommitment],
    l2_capacity_available: bool,
    l3_on_call_available: bool,
) -> list[str]:
    """
    Returns a list of warnings for commitments that may not be honoured.
    Incoming shift lead reviews this at shift start.
    """
    warnings = []
    for c in commitments:
        if c.fulfilled:
            continue
        if c.requires_tier == "L2" and not l2_capacity_available:
            warnings.append(
                f"{c.ticket_id}: commitment '{c.commitment_text}' requires L2 "                f"but L2 is at capacity — notify customer now"
            )
        if c.requires_tier == "L3" and not l3_on_call_available:
            warnings.append(
                f"{c.ticket_id}: commitment '{c.commitment_text}' requires L3 "                f"but L3 on-call is unavailable — escalate to support EM"
            )
        if c.is_at_risk():
            warnings.append(
                f"{c.ticket_id}: commitment due in < 1h and still not fulfilled"
            )
    return warnings
